import React, { memo } from "react";
import { motion } from "framer-motion";
import { useInView } from "react-intersection-observer";
import { Calendar, Search, Wrench, CheckCircle2 } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const steps = [
  {
    number: "01",
    title: "Broneeri aeg",
    description: "Saada p\u00e4ring vormist, WhatsAppist v\u00f5i helista. Vastame \u003c 1h.",
    detail: "Kinnitame aja ning vajadusel abistame transpordiga.",
    icon: Calendar
  },
  {
    number: "02",
    title: "Diagnostika",
    description: "Teeme s\u00fcsteemse \u00fclevaatuse ja jagame raportit foto/video toel.",
    detail: "Selgitame t\u00f6\u00f6 ulatuse ning kinnitame hinnangu.",
    icon: Search
  },
  {
    number: "03",
    title: "Professionaalne t\u00f6\u00f6",
    description: "Remondime ja hooldame OEM varuosade ning dokumenteeritud protseduuridega.",
    detail: "Hoiame sind kursis vahetule info ja vahev\u00f5tetega.",
    icon: Wrench
  },
  {
    number: "04",
    title: "\u00dcleandmine",
    description: "Teeme l\u00f5ppkontrolli, esitame tehtud t\u00f6\u00f6d ja anname garantii.",
    detail: "Kaasa saad hooldusplaani ning j\u00e4rmis(t)e sammude soovitused.",
    icon: CheckCircle2
  }
];

const StepCard = ({ step, index, isInView }) => {
  const Icon = step.icon;

  return (
    <motion.div
      initial={{ opacity: 0, y: 24 }}
      animate={isInView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.6, delay: index * 0.1 }}
      className="relative text-center group"
    >
      {index < steps.length - 1 && (
        <div className="hidden md:block absolute top-12 right-[-50%] w-full h-px bg-gradient-to-r from-transparent via-[#0F62FE]/40 to-transparent" aria-hidden="true" />
      )}
      <div className="flex flex-col items-center gap-4 rounded-3xl border border-white/50 bg-white/80 px-6 py-8 shadow-xl backdrop-blur dark:border-slate-800 dark:bg-slate-900/60">
        <div className="relative">
          <span className="absolute inset-0 rounded-full bg-[#0F62FE]/20 blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-300" aria-hidden="true" />
          <div className="w-16 h-16 rounded-full bg-gradient-to-br from-[#0F62FE] to-[#0FB5AF] text-white text-xl font-bold flex items-center justify-center shadow-lg relative z-10">
            {step.number}
          </div>
        </div>
        <div className="flex items-center gap-3">
          <div className="p-3 rounded-2xl bg-slate-100 text-[#0F62FE] dark:bg-slate-800 dark:text-[#0FB5AF] shadow-inner">
            <Icon className="h-6 w-6" aria-hidden="true" />
          </div>
          <h3 className="text-xl font-semibold text-slate-900 dark:text-slate-100">{step.title}</h3>
        </div>
        <p className="text-sm text-slate-700 dark:text-slate-300">{step.description}</p>
        <p className="text-xs uppercase tracking-wide text-slate-500 dark:text-slate-400">{step.detail}</p>
      </div>
    </motion.div>
  );
};

const ProcessSection = memo(() => {
  const [ref, inView] = useInView({ triggerOnce: true, threshold: 0.2 });

  return (
    <Section id="process" className="py-16">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/85 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardHeader className="text-center">
          <CardTitle className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
            Kuidas me t\u00f6\u00f6tame
          </CardTitle>
          <p className="mt-3 text-slate-800 dark:text-slate-300 text-base md:text-lg max-w-3xl mx-auto">
            L\u00e4bipaistev nelja sammuga protsess: kiire p\u00e4ring, dokumenteeritud diagnostika, kvaliteetne t\u00f6\u00f6 ning garantiiga \u00fcleandmine.
          </p>
        </CardHeader>
        <CardContent>
          <div ref={ref} className="grid grid-cols-1 md:grid-cols-4 gap-8">
            {steps.map((step, index) => (
              <StepCard key={step.number} step={step} index={index} isInView={inView} />
            ))}
          </div>
        </CardContent>
      </Card>
    </Section>
  );
});

ProcessSection.displayName = "ProcessSection";

export default ProcessSection;
